import{_ as s,a as o,b as t}from"./chunks/episodes.BMVYxuPH.js";import{_ as r,o as a,c as i,ag as n}from"./chunks/framework.DLWhSH9p.js";const c="/screenshots/mobile/login.png",d="/screenshots/mobile/discover.png",l="/screenshots/mobile/channel-deep.png",p="/screenshots/mobile/video-deep.png",h="/screenshots/mobile/ideas.png",g="/screenshots/mobile/idea-detail.png",m="/screenshots/mobile/scripts.png",u="/screenshots/mobile/episode-detail.png",b="/screenshots/mobile/audio-create.png",f="/screenshots/mobile/resources.png",v="/screenshots/mobile/proposals.png",w="/screenshots/mobile/jobs.png",_="/screenshots/mobile/more.png",y="/screenshots/mobile/settings.png",k="/screenshots/mobile/endpoints.png",M=JSON.parse('{"title":"Mobile Features","description":"","frontmatter":{},"headers":[],"relativePath":"mobile/features.md","filePath":"mobile/features.md"}'),T={name:"mobile/features.md"};function q(P,e,S,x,A,I){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="mobile-features" tabindex="-1">Mobile Features <a class="header-anchor" href="#mobile-features" aria-label="Permalink to &quot;Mobile Features&quot;">​</a></h1><p>A walkthrough of every screen in the Craft mobile app, in roughly the order you&#39;ll use them.</p><h2 id="sign-in" tabindex="-1">Sign in <a class="header-anchor" href="#sign-in" aria-label="Permalink to &quot;Sign in&quot;">​</a></h2><div class="mobile-screen"><img src="'+c+'" alt="Login screen"></div><p>The first time you launch Craft you&#39;ll land on the sign-in screen. Set the <strong>Server URL</strong> to your CRAFT deployment, tap <strong>Test connection</strong> to verify, then <strong>Login</strong> — Keycloak handles the auth flow in a system browser tab and you&#39;re sent back into the app.</p><p>The redirect URI shown on the login screen needs to be allowed in your Keycloak <code>mobile</code> client; ask your administrator if you hit &quot;Invalid parameter: redirect_uri.&quot;</p><h2 id="home" tabindex="-1">Home <a class="header-anchor" href="#home" aria-label="Permalink to &quot;Home&quot;">​</a></h2><div class="mobile-screen"><img src="'+s+'" alt="Home"></div><p>Home is the daily landing surface. The greeting summarizes what&#39;s waiting for you — scripts in review, episodes mid-pipeline. The four <strong>stage tiles</strong> (Discover, Ideas, Scripts, Episodes) jump you to each phase of the production lifecycle, and the <strong>Live now</strong> rail surfaces any episodes the AI agents are actively working on with their pipeline progress strip.</p><h2 id="discover" tabindex="-1">Discover <a class="header-anchor" href="#discover" aria-label="Permalink to &quot;Discover&quot;">​</a></h2><div class="mobile-screen-row"><img src="'+d+'" alt="Discover"><img src="'+l+'" alt="Channel deep dive"><img src="'+p+'" alt="Video deep dive"></div><p>Search YouTube without burning API quota — yt-dlp drives the search. The <strong>outlier slider</strong> boosts videos performing above their channel&#39;s baseline, and the <strong>channel chips</strong> group results so you can do a competitive read at a glance.</p><p>Tapping a channel opens a <strong>deep dive</strong> with subscriber count, growth rate, engagement, content mix, and estimated monthly earnings (uses your channel&#39;s RPM preset). Tapping a video shows the full transcript and lets you <strong>Inspire idea</strong> — pipes the metadata straight into the AI ideas generator with the source video as context.</p><h2 id="ideas" tabindex="-1">Ideas <a class="header-anchor" href="#ideas" aria-label="Permalink to &quot;Ideas&quot;">​</a></h2><div class="mobile-screen-row"><img src="'+h+'" alt="Ideas list"><img src="'+g+'" alt="Idea detail"></div><p>Three sources of ideas merge into one feed — AI-generated, Discover-imported, and manually written — each with a marker showing where it came from. The dashed-border <strong>Generate</strong> strip lets you drop in optional context and produce 5 ideas with the model of your choice. The Long/Shorts pill is a hard filter on what gets generated.</p><p>Idea detail shows the angle, source metrics, and tags. <strong>Convert to script</strong> kicks off the full production flow: creates the episode shell, spawns the script-generate worker, marks research as approved. <strong>YOLO</strong> runs the entire pipeline end-to-end without manual review.</p><h2 id="scripts" tabindex="-1">Scripts <a class="header-anchor" href="#scripts" aria-label="Permalink to &quot;Scripts&quot;">​</a></h2><div class="mobile-screen-row"><img src="'+m+'" alt="Scripts list"><img src="'+o+'" alt="Script editor"></div><p>The list shows each script with its <strong>type pill</strong> (long/short), <strong>status pill</strong> (draft / review / final), and <strong>word-count progress</strong> against the target (1500 for long, 150 for shorts).</p><p>The editor surfaces the four AI tools — <strong>Revise</strong>, <strong>Polish</strong>, <strong>Fact-check</strong>, <strong>Humanize</strong> — across the top. Fact-check opens a bottom sheet with verified / unverified / disputed claims, and Humanize shows the rewritten passages with a one-tap accept. Auto-save fires every 12 seconds. <strong>Send to audio</strong> is gated behind <code>review</code> or <code>final</code> status — drafts can&#39;t be sent.</p><h2 id="episodes-board" tabindex="-1">Episodes (Board) <a class="header-anchor" href="#episodes-board" aria-label="Permalink to &quot;Episodes (Board)&quot;">​</a></h2><div class="mobile-screen-row"><img src="'+t+'" alt="Episodes"><img src="'+u+'" alt="Episode detail"></div><p>Episodes is the production board. Each card shows the <strong>7-stage pipeline strip</strong> (research → script → storyboard → assets → export → review → publish) so you can see exactly where every episode is at a glance. Amber stages mean the producer agent flagged something for review.</p><p>Tap an episode for the per-stage detail view — each row shows status (running / queued / done / changes-requested) and the producer agent&#39;s feedback when a stage scored under 7/10.</p><h2 id="audio" tabindex="-1">Audio <a class="header-anchor" href="#audio" aria-label="Permalink to &quot;Audio&quot;">​</a></h2><div class="mobile-screen"><img src="'+b+'" alt="Audio production"></div><p>The four TTS providers (Edge free, ElevenLabs, OpenAI, OpenedAI Speech) live across the top. Voice tuning sliders adjust stability, similarity, and inter-section pause. Each section has its own <strong>render</strong>, <strong>play</strong>, and <strong>mic</strong> controls — tap the mic to record a take from your phone, which uploads as the section&#39;s voice (replacing the TTS output). The MusicGen background track is generated from a text prompt and mixed under the voice during the merge.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><div class="mobile-screen"><img src="'+f+'" alt="Resources"></div><p>Search across 14 royalty-free media sources — Pexels, Unsplash, Wikimedia Commons, NASA, Met Museum, and more. The <strong>type tabs</strong> (video / image / audio / reference) scope the search; the <strong>source toggles</strong> let you opt out of providers you don&#39;t want. CC0 / PD badges surface license info inline. Tap <strong>Upload</strong> in the top bar to add your own media via the system file picker.</p><h2 id="proposals-jobs-premium" tabindex="-1">Proposals &amp; Jobs (Premium) <a class="header-anchor" href="#proposals-jobs-premium" aria-label="Permalink to &quot;Proposals &amp; Jobs (Premium)&quot;">​</a></h2><div class="mobile-screen-row"><img src="'+v+'" alt="Proposals"><img src="'+w+'" alt="Jobs"></div><p>Proposals are AI-scored content suggestions — relevance to your existing catalog, uniqueness in your niche, and character fit (averaged into the lead score). <strong>Accept</strong> spawns an idea + script + queues research; <strong>YOLO</strong> one-shots the entire pipeline.</p><p>Jobs shows every async worker invocation with live status — running, queued, completed, failed. The mobile app polls every 3 seconds (the web frontend uses SSE; React Native&#39;s fetch lacks ReadableStream, so polling is the workaround).</p><h2 id="more" tabindex="-1">More <a class="header-anchor" href="#more" aria-label="Permalink to &quot;More&quot;">​</a></h2><div class="mobile-screen-row"><img src="'+_+'" alt="More menu"><img src="'+y+'" alt="Settings"><img src="'+k+'" alt="Endpoint health"></div><p>The More menu is a flat tray for everything that didn&#39;t earn a permanent bottom-nav slot — Scripts, Episodes, Resources, Proposals, Jobs, Channel settings, Endpoint health, Sign out. Premium-only items are visually marked but never gated until tapped (discoverability over conversion friction).</p><p><strong>Settings</strong> is the channel control panel: character description, default voice, RPM for earnings estimates, topic tags, API keys, billing chip, publishing connections, brand templates, and the AI channel wizard.</p><p><strong>Endpoint health</strong> is a refactor appendix — diff of <code>mobile/src/lib/api.ts</code> against the live backend, grouped by section, with status pills for <code>ok</code> / <code>mismatch</code> / <code>add</code> and inline notes for each gap.</p>',40)])])}const C=r(T,[["render",q]]);export{M as __pageData,C as default};
